svg.script:
    (function () {
      var root = document.querySelector('svg > g[id], g[id]');
      if (!root) {
        return;
      }

      var legendItem = root.querySelector('.legend-item');
      var legendContainer = legendItem ? legendItem.querySelector('rect.legend-item-container') : null;
      var legendLabel = legendItem ? legendItem.querySelector('text.legend-label') : null;
      var bars = Array.prototype.slice.call(root.querySelectorAll('.bars rect[data-bar-key]'));
      var axisLabels = Array.prototype.slice.call(root.querySelectorAll('.data-series > .a > .axis-labels text[data-bar-key]'));
      var valueLabels = Array.prototype.slice.call(root.querySelectorAll('.bar-value-label[data-bar-key]'));

      if (!legendItem || bars.length === 0 || axisLabels.length === 0 || valueLabels.length === 0) {
        return;
      }

      if (!legendItem.hasAttribute('tabindex')) {
        legendItem.setAttribute('tabindex', '0');
      }
      legendItem.style.cursor = 'pointer';

      if (legendContainer) {
        legendContainer.style.transition = 'opacity 220ms ease-in-out, stroke 220ms ease-in-out, stroke-width 220ms ease-in-out';
      }

      if (legendLabel) {
        legendLabel.style.transition = 'opacity 220ms ease-in-out';
      }

      function setLabelTypography(label, size, weight) {
        label.style.fontSize = size;
        label.style.fontWeight = weight;
        Array.prototype.forEach.call(label.querySelectorAll('tspan'), function (span) {
          span.style.fontSize = size;
          span.style.fontWeight = weight;
        });
      }

      bars.forEach(function (bar) {
        bar.style.cursor = 'pointer';
        bar.style.transition = 'fill-opacity 220ms ease-in-out, opacity 220ms ease-in-out';
      });

      axisLabels.forEach(function (label) {
        label.style.cursor = 'pointer';
        label.style.transition = 'opacity 220ms ease-in-out';
      });

      valueLabels.forEach(function (label) {
        if (!label.style.transition) {
          label.style.transition = 'opacity 220ms ease-in-out, font-size 220ms ease-in-out, fill-opacity 220ms ease-in-out';
        }
      });

      var activeMode = null;
      var activeBarKey = null;

      function renderState() {
        var isSeriesActive = activeMode === 'series';

        if (legendContainer) {
          legendContainer.style.stroke = isSeriesActive ? 'var(--color-text-dark)' : '';
          legendContainer.style.strokeWidth = isSeriesActive ? '1.5' : '';
        }

        bars.forEach(function (bar) {
          var isBarActive = activeMode === 'bar' && bar.getAttribute('data-bar-key') === activeBarKey;
          if (isSeriesActive || isBarActive) {
            bar.style.fillOpacity = '1';
          } else {
            bar.style.removeProperty('fill-opacity');
          }
        });

        valueLabels.forEach(function (label) {
          var isHoverOnly = label.classList.contains('hover-only');
          var isLabelActive = isSeriesActive || (activeMode === 'bar' && label.getAttribute('data-bar-key') === activeBarKey);

          if (isLabelActive) {
            label.style.opacity = '1';
            setLabelTypography(label, '14px', '700');
            label.style.fillOpacity = '1';
          } else {
            label.style.opacity = isHoverOnly ? '0' : '';
            setLabelTypography(label, '10px', '600');
            label.style.removeProperty('fill-opacity');
          }
        });
      }

      function activateSeries() {
        activeMode = 'series';
        activeBarKey = null;
        renderState();
      }

      function clearSeries() {
        if (activeMode === 'series') {
          activeMode = null;
          activeBarKey = null;
          renderState();
        }
      }

      function activateBar(barKey) {
        activeMode = 'bar';
        activeBarKey = barKey;
        renderState();
      }

      function clearBar(barKey) {
        if (activeMode === 'bar' && activeBarKey === barKey) {
          activeMode = null;
          activeBarKey = null;
          renderState();
        }
      }

      legendItem.addEventListener('mouseenter', activateSeries);
      legendItem.addEventListener('mouseleave', clearSeries);
      legendItem.addEventListener('focus', activateSeries);
      legendItem.addEventListener('blur', clearSeries);

      bars.forEach(function (bar) {
        var barKey = bar.getAttribute('data-bar-key');

        bar.addEventListener('mouseenter', function () {
          activateBar(barKey);
        });

        bar.addEventListener('mouseleave', function () {
          clearBar(barKey);
        });
      });

      axisLabels.forEach(function (label) {
        var barKey = label.getAttribute('data-bar-key');

        label.addEventListener('mouseenter', function () {
          activateBar(barKey);
        });

        label.addEventListener('mouseleave', function () {
          clearBar(barKey);
        });
      });

      renderState();
    }());
